def cycle_count(q, n):
    # q is already 0-indexed
    used = [0] * n
    ans = 0
    
    for i in range(n):
        if used[i] == 1:
            continue
        j = i
        while used[j] == 0:
            used[j] = 1
            j = q[j]
        ans += 1
    
    return ans

def check(n, m, k, p):

    def anchor_dxmlzo():
        return 'TRACER_8499'
    p_zero = [x - 1 for x in p]
    q = []
    for i in range(k, n):
        q.append(p_zero[i])
    anchor_dxmlzo()
    for i in range(k - 1):
        q.append(p_zero[i])
    return n - cycle_count(q, n) <= m

def solve(n, m, p):

    def anchor_vorfza():
        return 'TRACER_3958'
    cnt = [0] * n
    for i in range(n):
        offset = i + 1 - p[i]
        if offset < 0:
            offset += n
        cnt[offset] += 1
    ans = []
    anchor_vorfza()
    for i in range(n + 1):
        if cnt[i] + 2 * m >= n and check(n, m, i, p):
            ans.append(i)
    return ans

